import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import Header from './Header';

const API_ENDPOINTS = [
  {
    name: 'Save RFID Transaction Details',
    endpoint: 'SaveRFIDTransactionDetails',
    method: 'POST',
    description: 'Save new RFID transaction details to the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-save',
    behavioralCases: [
      {
        title: 'Case 1: RFID Number Already Exists with Status "ApiActive" or "Active"',
        description: 'The existing record will be updated with the new details (category, product, weight, item code, box details, etc.)'
      },
      {
        title: 'Case 2: RFID Number Does Not Exist in tblLabelledStock',
        description: 'A new record will be inserted with the provided details.'
      },
      {
        title: 'Case 3: RFID Number Exists but with a Different Status',
        description: 'If the barcode exists but has a different status (not "ApiActive" or "Active"), the API will create a new record instead of updating.'
      }
    ],
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "ItemCode": "ITEM001",
      "CategoryId": 1,
      "ProductId": 2,
      "DesignId": 3,
      "PurityId": 4,
      "GrossWeight": "10.50",
      "NetWeight": "9.80",
      "BoxNumber": "BOX001",
      "Status": "ApiActive"
    }
  },
  {
    name: 'Update RFID Transaction Details',
    endpoint: 'UpdateRFIDTransactionDetails',
    method: 'POST',
    description: 'Update the status of the product to Active or Sold based on the RFID Number.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-edit',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumber": "RFID123456789",
      "Status": "Sold" // Can be "Sold" or "Active"
    }
  },
  {
    name: 'Get RFID Transaction Details',
    endpoint: 'GetRFIDTransactionDetails',
    method: 'POST',
    description: 'Retrieve all records from the inventory stock table.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: false,
    icon: 'fas fa-search',
    sampleBody: {
      "ClientCode": "" // Will be filled dynamically
    }
  },
  {
    name: 'Delete Labelled Stock Items',
    endpoint: 'DeleteLabelledStockItems',
    method: 'POST',
    description: 'Delete one or more items using ClientCode, RFID Number, or ItemCode.',
    baseUrl: 'https://soni.loyalstring.co.in/api/ProductMaster',
    authRequired: true,
    icon: 'fas fa-trash',
    sampleBody: {
      "ClientCode": "", // Will be filled dynamically
      "RFIDNumbers": ["RFID123456789", "RFID987654321"],
      "ItemCodes": ["ITEM001", "ITEM002"]
    }
  }
];

const Dashboard = () => {
  const [selectedApi, setSelectedApi] = useState(null);
  const [requestBody, setRequestBody] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [token, setToken] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const storedToken = localStorage.getItem('token');
    const storedUserInfo = localStorage.getItem('userInfo');
    
    if (!storedToken) {
      navigate('/login');
      return;
    }

    // Validate token and extract client code
    try {
      const tokenData = JSON.parse(atob(storedToken.split('.')[1]));
      if (!tokenData.ClientCode) {
        throw new Error('Invalid token: No client code found');
      }
      setToken(storedToken);
      
      if (storedUserInfo) {
        const parsedUserInfo = JSON.parse(storedUserInfo);
        // Verify that stored userInfo matches token data
        if (parsedUserInfo.ClientCode !== tokenData.ClientCode) {
          console.warn('Stored client code does not match token. Using token data.');
          parsedUserInfo.ClientCode = tokenData.ClientCode;
          localStorage.setItem('userInfo', JSON.stringify(parsedUserInfo));
        }
        setUserInfo(parsedUserInfo);
      } else {
        // Create userInfo from token if not in localStorage
        const userInfo = {
          Username: tokenData.sub,
          ClientCode: tokenData.ClientCode
        };
        localStorage.setItem('userInfo', JSON.stringify(userInfo));
        setUserInfo(userInfo);
      }
    } catch (err) {
      console.error('Token validation error:', err);
      localStorage.removeItem('token');
      localStorage.removeItem('userInfo');
      navigate('/login');
    }
  }, [navigate]);

  const handleApiSelect = (api) => {
    setSelectedApi(api);
    let sampleBodyCopy = JSON.parse(JSON.stringify(api.sampleBody));
    
    // Handle both array and object request bodies
    if (Array.isArray(sampleBodyCopy)) {
      sampleBodyCopy = sampleBodyCopy.map(item => ({
        ...item,
        ClientCode: userInfo?.ClientCode || ''
      }));
    } else {
      sampleBodyCopy = {
        ...sampleBodyCopy,
        ClientCode: userInfo?.ClientCode || ''
      };
    }
    
    setRequestBody(JSON.stringify(sampleBodyCopy, null, 2));
    setResponse('');
    setError('');
  };

  const handleSendRequest = async () => {
    if (!selectedApi) return;

    setLoading(true);
    setError('');
    setResponse('');

    try {
      const config = {
        headers: {
          'Content-Type': 'application/json'
        }
      };

      if (selectedApi.authRequired) {
        if (!token) {
          throw new Error('Authentication token is required for this endpoint');
        }
        config.headers['Authorization'] = `Bearer ${token}`;
      }

      const url = `${selectedApi.baseUrl}/${selectedApi.endpoint}`;
      let parsedBody;
      
      try {
        parsedBody = JSON.parse(requestBody);
      } catch (e) {
        throw new Error('Invalid JSON in request body');
      }

      // Validate client code
      if (!parsedBody.ClientCode) {
        throw new Error('ClientCode is required');
      }

      const result = await axios.post(url, parsedBody, config);

      if (result.data.Status === false) {
        throw new Error(result.data.Message || 'Operation failed');
      }

      setResponse(JSON.stringify(result.data, null, 2));
      toast.success(result.data.Message || 'API request successful!');
    } catch (err) {
      console.error('API Error:', err);
      const errorMessage = err.response?.data?.Message || err.message || 'An error occurred while making the request.';
      setError(errorMessage);
      toast.error(errorMessage);
      
      if (err.response?.status === 401) {
        toast.error('Authentication failed. Please login again.');
        localStorage.removeItem('token');
        localStorage.removeItem('userInfo');
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="d-flex flex-column min-vh-100">
      <Header userInfo={userInfo} />
      <ToastContainer />
      <div className="container-fluid flex-grow-1 p-4">
        <div className="row h-100">
          {/* Sidebar */}
          <div className="col-md-3">
            <div className="card mb-4" style={{ 
              background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
              boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
            }}>
              <div className="card-header bg-primary text-white">
                <h5 className="mb-0">
                  <i className="fas fa-book me-2"></i>
                  API Documentation
                </h5>
              </div>
              <div className="list-group list-group-flush">
                {API_ENDPOINTS.map((api, index) => (
                  <button
                    key={index}
                    className={`list-group-item list-group-item-action ${
                      selectedApi?.endpoint === api.endpoint ? 'active' : ''
                    }`}
                    onClick={() => handleApiSelect(api)}
                  >
                    <div className="d-flex align-items-center">
                      <span className={`badge me-2 ${api.method === 'POST' ? 'bg-success' : 'bg-primary'}`}>
                        {api.method}
                      </span>
                      <div>
                        <div className="fw-bold">{api.name}</div>
                        <small className="text-muted">/api/ProductMaster/{api.endpoint}</small>
                      </div>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Main Content */}
          <div className="col-md-9">
            {selectedApi ? (
              <div className="card" style={{ 
                background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
                boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
              }}>
                {/* API Header */}
                <div className="card-header bg-dark text-white">
                  <div className="d-flex justify-content-between align-items-center">
                    <div>
                      <h4 className="mb-0">
                        <span className={`badge me-2 ${selectedApi.method === 'POST' ? 'bg-success' : 'bg-primary'}`}>
                          {selectedApi.method}
                        </span>
                        {selectedApi.name}
                      </h4>
                      <small>/api/ProductMaster/{selectedApi.endpoint}</small>
                    </div>
                  </div>
                </div>

                <div className="card-body">
                  {/* Description */}
                  <div className="mb-4">
                    <h5>Description</h5>
                    <p>{selectedApi.description}</p>
                  </div>

                  {/* Authentication */}
                  <div className="mb-4">
                    <h5>Authentication</h5>
                    <div className="d-flex align-items-center">
                      <span className="badge bg-warning me-2">
                        <i className="fas fa-lock me-1"></i>
                        Required
                      </span>
                      <small className="text-muted">Bearer Token: {token.substring(0, 20)}...</small>
                    </div>
                  </div>

                  {/* Behavioral Cases */}
                  {selectedApi.behavioralCases && (
                    <div className="mb-4">
                      <h5>Behavioral Cases</h5>
                      <div className="accordion" id="behavioralCases">
                        {selectedApi.behavioralCases.map((caseItem, index) => (
                          <div className="accordion-item" key={index}>
                            <h2 className="accordion-header">
                              <button
                                className="accordion-button collapsed"
                                type="button"
                                data-bs-toggle="collapse"
                                data-bs-target={`#case${index}`}
                              >
                                {caseItem.title}
                              </button>
                            </h2>
                            <div
                              id={`case${index}`}
                              className="accordion-collapse collapse"
                              data-bs-parent="#behavioralCases"
                            >
                              <div className="accordion-body">
                                {caseItem.description}
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Request Body */}
                  <div className="mb-4">
                    <h5>Request Body</h5>
                    <div className="mb-3">
                      <textarea
                        className="form-control font-monospace"
                        rows="10"
                        value={requestBody}
                        onChange={(e) => setRequestBody(e.target.value)}
                      />
                    </div>
                    <button
                      className="btn btn-primary"
                      onClick={handleSendRequest}
                      disabled={loading}
                    >
                      {loading ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                          Executing...
                        </>
                      ) : (
                        <>
                          <i className="fas fa-play-circle me-2"></i>
                          Execute
                        </>
                      )}
                    </button>
                  </div>

                  {/* Response */}
                  {(response || error) && (
                    <div className="mb-4">
                      <h5>Response</h5>
                      {error && (
                        <div className="alert alert-danger">
                          <i className="fas fa-exclamation-circle me-2"></i>
                          {error}
                        </div>
                      )}
                      {response && (
                        <div className="bg-light p-3 rounded">
                          <div className="d-flex justify-content-between align-items-center mb-2">
                            <span className="badge bg-success">200 OK</span>
                          </div>
                          <pre className="mb-0">
                            <code>{response}</code>
                          </pre>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            ) : (
              <div className="card h-100 d-flex align-items-center justify-content-center" style={{ 
                background: 'linear-gradient(135deg, #ffffff 0%, #f8f9fa 100%)',
                boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
              }}>
                <div className="text-center p-5">
                  <i className="fas fa-book fa-3x text-primary mb-3"></i>
                  <h3>RFID API Documentation</h3>
                  <p className="text-muted">Select an API endpoint from the sidebar to view documentation and test the API.</p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
